mapper.insert:
INSERT INTO users (user_id, user_pw, user_name, birth, gender, phone, address)
VALUES (
    #{userId}, #{userPw}, #{userName},
    TO_DATE(#{birth}, 'YYYY-MM-DD'),
    #{gender}, #{phone}, #{address}
)

mapper.select:
select * from (
    select rownum as rn, A.* from (
        SELECT user_id, user_pw, user_name,
               TO_CHAR(birth, 'YYYY-MM-DD') AS birth,
               gender, phone, address, is_admin, member_status
        FROM users
    ) A
    where rownum <= #{endRow}
)
where rn >= #{startRow}

mapper.update:
UPDATE users
SET user_name = #{userName},
    birth     = TO_DATE(#{birth}, 'YYYY-MM-DD'),
    gender    = #{gender},
    phone     = #{phone},
    address   = #{address}
    
        , user_pw = #{userPw}
    
WHERE user_id = #{userId}

